// PDF Folder Scanner
const fs = require('fs');
const path = require('path');

// Get folder path from input or use default
const folderPath = $json.body.folder_path || '/app/ocr_storage/input';

try {
  // Read all files from folder
  const files = fs.readdirSync(folderPath);

  // Filter for PDF files
  const pdfFiles = files.filter(file => 
    file.toLowerCase().endsWith('.pdf')
  );

  // Create array of file objects
  const fileList = pdfFiles.map(filename => ({
    filename: filename,
    filepath: path.join(folderPath, filename),
    processing_status: 'pending'
  }));

  return fileList.map(file => ({ json: file }));

} catch (error) {
  throw new Error(`Failed to read folder ${folderPath}: ${error.message}`);
}

// PDF Type Detection (Text vs Image PDF)
const fs = require('fs');
const { execSync } = require('child_process');

const filepath = $json.filepath;
const filename = $json.filename;

try {
  // Use pdftotext to extract text and check if meaningful text exists
  const command = `pdftotext "${filepath}" - | wc -c`;
  const textLength = parseInt(execSync(command, { encoding: 'utf8' }).trim());

  // If more than 100 characters of extractable text, consider it a text PDF
  const isTextPdf = textLength > 100;

  return {
    json: {
      filename: filename,
      filepath: filepath,
      pdf_type: isTextPdf ? 'text' : 'image',
      extractable_text_length: textLength,
      needs_ocr: !isTextPdf
    }
  };

} catch (error) {
  // If pdftotext fails, assume it's an image PDF
  return {
    json: {
      filename: filename,
      filepath: filepath,
      pdf_type: 'image',
      extractable_text_length: 0,
      needs_ocr: true,
      detection_error: error.message
    }
  };
}

// Extract text directly from text PDF
const { execSync } = require('child_process');
const filepath = $json.filepath;
const filename = $json.filename;

try {
  // Extract text using pdftotext
  const command = `pdftotext "${filepath}" -`;
  const extractedText = execSync(command, { encoding: 'utf8' });

  return {
    json: {
      filename: filename,
      filepath: filepath,
      source: 'direct_text_extraction',
      extracted_text: extractedText,
      processing_time: 0.1,
      confidence_score: 1.0
    }
  };

} catch (error) {
  throw new Error(`Failed to extract text from ${filename}: ${error.message}`);
}

// Prepare file for OCR processing
const fs = require('fs');
const filepath = $json.filepath;
const filename = $json.filename;

// Read file as binary data
const fileBuffer = fs.readFileSync(filepath);

return {
  json: {
    filename: filename,
    filepath: filepath,
    source: 'ocr_processing'
  },
  binary: {
    data: fileBuffer
  }
};

// Normalize OCR result for Ollama processing
const ocrResult = $json;
const filename = $('prepare-for-ocr').first().json.filename;

return {
  json: {
    filename: filename,
    source: 'ocr_processing',
    extracted_text: ocrResult.text || ocrResult.extracted_text || '',
    processing_time: ocrResult.processing_time || 0,
    confidence_score: ocrResult.confidence_score || 0,
    engine_used: ocrResult.engine_used || 'unknown'
  }
};

