// Process and validate Ollama response
const ollamaResponse = $json.response || $json.text || '';
const sourceData = $input.first().json;

try {
  // Try to parse JSON from Ollama response
  let extractedData;

  // Clean response - remove markdown code blocks if present
  const cleanResponse = ollamaResponse
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  try {
    extractedData = JSON.parse(cleanResponse);
  } catch (parseError) {
    // If JSON parsing fails, try to extract JSON from text
    const jsonMatch = cleanResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      extractedData = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found in response');
    }
  }

  // Build final result
  const result = {
    success: true,
    timestamp: new Date().toISOString(),
    source_file: sourceData.filename,
    processing_method: sourceData.source,
    confidence_score: sourceData.confidence_score,
    processing_time_seconds: sourceData.processing_time,
    extracted_invoice_data: extractedData,
    metadata: {
      engine_used: sourceData.engine_used || 'direct_extraction',
      text_length: (sourceData.extracted_text || '').length,
      extraction_model: 'llama3.2:latest'
    }
  };

  return { json: result };

} catch (error) {
  // Return error response
  return {
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      source_file: sourceData.filename,
      error: error.message,
      raw_response: ollamaResponse,
      metadata: {
        processing_method: sourceData.source,
        confidence_score: sourceData.confidence_score
      }
    }
  };
}

// Aggregate all processing results
const allResults = $input.all();

const summary = {
  success: true,
  timestamp: new Date().toISOString(),
  total_files_processed: allResults.length,
  successful_extractions: allResults.filter(item => item.json.success).length,
  failed_extractions: allResults.filter(item => !item.json.success).length,
  processing_summary: {
    text_pdfs: allResults.filter(item => 
      item.json.metadata?.processing_method === 'direct_text_extraction'
    ).length,
    image_pdfs_ocr: allResults.filter(item => 
      item.json.metadata?.processing_method === 'ocr_processing'
    ).length
  },
  results: allResults.map(item => item.json)
};

return { json: summary };
